selector_to_html = {"a[href=\"#modelo-conformable-con-sigma\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Modelo conformable con <span class=\"math notranslate nohighlight\">\\(\\sigma\\)</span><a class=\"headerlink\" href=\"#modelo-conformable-con-sigma\" title=\"Link to this heading\">#</a></h2><h3>Funci\u00f3n objetivo para realizar la optimizaci\u00f3n<a class=\"headerlink\" href=\"#funcion-objetivo-para-realizar-la-optimizacion\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#parametros-adimensionales\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Par\u00e1metros adimensionales<a class=\"headerlink\" href=\"#parametros-adimensionales\" title=\"Link to this heading\">#</a></h3><p><strong>Frecuencia Natural</strong></p>", "a[href=\"#equation-e269ea90-739c-4002-a8f5-042633d7bef2\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-e269ea90-739c-4002-a8f5-042633d7bef2\">\n\\[\\begin{equation}\n \\omega_n = \\sqrt{\\frac{k}{m}} \\quad \\text{[rad/s]}.\n\\end{equation}\\]</div>", "a[href=\"#ejemplo-de-parametros-de-simulacion\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Ejemplo de Par\u00e1metros de Simulaci\u00f3n<a class=\"headerlink\" href=\"#ejemplo-de-parametros-de-simulacion\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#equation-520cf738-6940-41d1-ab7a-7ef37903c392\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-520cf738-6940-41d1-ab7a-7ef37903c392\">\n\\[\\begin{equation}\n x(t) = Ae^{\\lambda_1 t} + Be^{\\lambda_2 t}.\n\\end{equation}\\]</div>", "a[href=\"#componentes-de-fuerza\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Componentes de Fuerza<a class=\"headerlink\" href=\"#componentes-de-fuerza\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#carga-de-datos-experimentales-y-preparacion-para-el-modelado-conformable\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Carga de datos experimentales y preparaci\u00f3n para el modelado conformable<a class=\"headerlink\" href=\"#carga-de-datos-experimentales-y-preparacion-para-el-modelado-conformable\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#equation-b69bbe0d-e195-4ebc-b69c-9a4dc2019b87\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-b69bbe0d-e195-4ebc-b69c-9a4dc2019b87\">\n\\[\\begin{equation}\n \\lambda_{1,2} = -\\frac{c}{2m} \\pm \\sqrt{\\left(\\frac{c}{2m}\\right)^2 - \\frac{k}{m}}.\n\\end{equation}\\]</div>", "a[href=\"#equation-f0c2c7b3-5c9e-4257-b94a-fc68b63e654d\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-f0c2c7b3-5c9e-4257-b94a-fc68b63e654d\">\n\\[\\begin{equation}\n x(t) = (A + Bt)e^{-\\omega_n t}.\n\\end{equation}\\]</div>", "a[href=\"#equation-4df0ffa4-11ad-469b-b617-a443dcd97456\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-4df0ffa4-11ad-469b-b617-a443dcd97456\">\n\\[\\begin{equation}\n m\\frac{d^2x}{dt^2} + c\\frac{dx}{dt} + kx = 0,\n\\end{equation}\\]</div>", "a[href=\"#superposicion-del-modelo-clasico-y-el-modelo-conformable\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Superposici\u00f3n del modelo cl\u00e1sico y el modelo conformable<a class=\"headerlink\" href=\"#superposicion-del-modelo-clasico-y-el-modelo-conformable\" title=\"Link to this heading\">#</a></h2><p>Con un valor de <span class=\"math notranslate nohighlight\">\\(\\alpha\\)</span>, el modelo conformable replica el comportamiento que presentar\u00eda el modelo cl\u00e1sico. Para profundizar en la validaci\u00f3n del modelo, es preciso considerar tambi\u00e9n la inclusi\u00f3n de la variable <span class=\"math notranslate nohighlight\">\\(\\sigma\\)</span>. Esto es</p>", "a[href=\"#optimizacion-multietapa\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Optimizaci\u00f3n multietapa<a class=\"headerlink\" href=\"#optimizacion-multietapa\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#equation-c54fa10a-e2b5-4b60-948e-a8e5b2154498\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-c54fa10a-e2b5-4b60-948e-a8e5b2154498\">\n\\[\\begin{equation}\n \\zeta = \\frac{c}{2\\sqrt{km}}.\n\\end{equation}\\]</div>", "a[href=\"#sistema-masa-resorte-amortiguador-sobreamortiguado\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Sistema masa resorte amortiguador (sobreamortiguado)<a class=\"headerlink\" href=\"#sistema-masa-resorte-amortiguador-sobreamortiguado\" title=\"Link to this heading\">#</a></h1><h2>Modelo cl\u00e1sico<a class=\"headerlink\" href=\"#modelo-clasico\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#modelo-matematico\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Modelo Matem\u00e1tico<a class=\"headerlink\" href=\"#modelo-matematico\" title=\"Link to this heading\">#</a></h2><h3>Ecuaci\u00f3n diferencial gobernante<a class=\"headerlink\" href=\"#ecuacion-diferencial-gobernante\" title=\"Link to this heading\">#</a></h3><p>El sistema se rige por la segunda Ley de Newton</p>", "a[href=\"#equation-fb877fa1-ec7f-4335-b3e1-365d8e77b22f\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-fb877fa1-ec7f-4335-b3e1-365d8e77b22f\">\n\\[\\begin{equation}\n x(t) = A\\cos(\\omega_n t) + B\\sin(\\omega_n t).\n\\end{equation}\\]</div>", "a[href=\"#tipos-de-solucion-segun-la-razon-de-amortiguamiento\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Tipos de soluci\u00f3n seg\u00fan la raz\u00f3n de amortiguamiento<a class=\"headerlink\" href=\"#tipos-de-solucion-segun-la-razon-de-amortiguamiento\" title=\"Link to this heading\">#</a></h2><h3>Sistema no amortiguado (<span class=\"math notranslate nohighlight\">\\(\\zeta = 0\\)</span>)<a class=\"headerlink\" href=\"#sistema-no-amortiguado-zeta-0\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#equation-c201e75f-6c22-4362-a53a-a1ff3968dc22\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-c201e75f-6c22-4362-a53a-a1ff3968dc22\">\n\\[\\begin{equation}\n \\omega_d = \\omega_n\\sqrt{1-\\zeta^2} \\quad \\text{(para } \\zeta &lt; 1\\text{)}.\n\\end{equation}\\]</div>", "a[href=\"#balance-de-energia\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Balance de Energ\u00eda<a class=\"headerlink\" href=\"#balance-de-energia\" title=\"Link to this heading\">#</a></h3><p><strong>Energ\u00eda Total = Energ\u00eda Cin\u00e9tica + Energ\u00eda Potencial + Energ\u00eda Disipada</strong></p>", "a[href=\"#equation-dd9529f9-ee3e-4ac4-b56f-5a6157d9b169\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-dd9529f9-ee3e-4ac4-b56f-5a6157d9b169\">\n\\[\\begin{equation}\n x(t) = e^{-\\zeta\\omega_n t}\\left[A\\cos(\\omega_d t) + B\\sin(\\omega_d t)\\right].\n\\end{equation}\\]</div>", "a[href=\"#interpretacion-fisica\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Interpretaci\u00f3n F\u00edsica<a class=\"headerlink\" href=\"#interpretacion-fisica\" title=\"Link to this heading\">#</a></h2><h3>Balance de Energ\u00eda<a class=\"headerlink\" href=\"#balance-de-energia\" title=\"Link to this heading\">#</a></h3><p><strong>Energ\u00eda Total = Energ\u00eda Cin\u00e9tica + Energ\u00eda Potencial + Energ\u00eda Disipada</strong></p>", "a[href=\"#graficacion-del-ajuste-optimizado-vs-datos-sinteticos\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Graficaci\u00f3n del ajuste optimizado vs. datos sint\u00e9ticos<a class=\"headerlink\" href=\"#graficacion-del-ajuste-optimizado-vs-datos-sinteticos\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#obtencion-de-datos\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Obtenci\u00f3n de datos<a class=\"headerlink\" href=\"#obtencion-de-datos\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#equation-8d5cc6cb-b7b3-45fd-adec-47d6cfe87b92\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-8d5cc6cb-b7b3-45fd-adec-47d6cfe87b92\">\n\\[\\begin{equation}\n E(t) = \\underbrace{\\frac{1}{2}m\\dot{x}^2}_{\\text{Cin\u00e9tica}} + \\underbrace{\\frac{1}{2}kx^2}_{\\text{Potencial}} + \\underbrace{\\int_0^t c\\dot{x}^2\\,dt}_{\\text{Disipada}}\n\\end{equation}\\]</div>", "a[href=\"#equation-8fc1ecf7-23eb-4b38-bb55-e1f964e0bdbb\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-8fc1ecf7-23eb-4b38-bb55-e1f964e0bdbb\">\n\\[\\begin{equation}\n \\frac{1}{\\sigma^{1-\\alpha}}~ {}^{K}\\mathcal{D}_{t}^{\\alpha}~ f(t) = \\frac{1}{\\sigma^{1-\\alpha}} t^{1-\\alpha} \\frac{df}{dt},\n\\end{equation}\\]</div>", "a[href=\"#sistema-con-amortiguamiento-critico-zeta-1\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Sistema con amortiguamiento cr\u00edtico (<span class=\"math notranslate nohighlight\">\\(\\zeta = 1\\)</span>)<a class=\"headerlink\" href=\"#sistema-con-amortiguamiento-critico-zeta-1\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#sistema-sobreamortiguado-zeta-1\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Sistema sobreamortiguado (<span class=\"math notranslate nohighlight\">\\(\\zeta &gt; 1\\)</span>)<a class=\"headerlink\" href=\"#sistema-sobreamortiguado-zeta-1\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#sistema-subamortiguado-0-zeta-1\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Sistema subamortiguado (<span class=\"math notranslate nohighlight\">\\(0 &lt; \\zeta &lt; 1\\)</span>)<a class=\"headerlink\" href=\"#sistema-subamortiguado-0-zeta-1\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#funcion-objetivo-para-realizar-la-optimizacion\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Funci\u00f3n objetivo para realizar la optimizaci\u00f3n<a class=\"headerlink\" href=\"#funcion-objetivo-para-realizar-la-optimizacion\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#ecuacion-diferencial-gobernante\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Ecuaci\u00f3n diferencial gobernante<a class=\"headerlink\" href=\"#ecuacion-diferencial-gobernante\" title=\"Link to this heading\">#</a></h3><p>El sistema se rige por la segunda Ley de Newton</p>", "a[href=\"#equation-741f07fa-c721-4366-bf36-c289b52b2c61\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-741f07fa-c721-4366-bf36-c289b52b2c61\">\n\\[\\begin{equation}\n m\\lambda^2 + c\\lambda + k = 0,\n\\end{equation}\\]</div>", "a[href=\"#perfil-de-verosimilitud-para-sigma\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Perfil de verosimilitud para <span class=\"math notranslate nohighlight\">\\(\\sigma\\)</span><a class=\"headerlink\" href=\"#perfil-de-verosimilitud-para-sigma\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#modelo-conformable-con-alpha-to-1\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Modelo conformable con <span class=\"math notranslate nohighlight\">\\(\\alpha \\to 1\\)</span><a class=\"headerlink\" href=\"#modelo-conformable-con-alpha-to-1\" title=\"Link to this heading\">#</a></h2><p>Establecemos <span class=\"math notranslate nohighlight\">\\(\\alpha\\)</span> en un valor extremadamente cercano a 1 (<span class=\"math notranslate nohighlight\">\\(0.99999\\)</span>) y comparamos el resultado con el modelo cl\u00e1sico. La diferencia deber\u00eda ser m\u00ednima, lo que confirma que la implementaci\u00f3n conformable es correcta.</p>", "a[href=\"#ecuacion-caracteristica-del-sistema\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Ecuaci\u00f3n caracter\u00edstica del sistema<a class=\"headerlink\" href=\"#ecuacion-caracteristica-del-sistema\" title=\"Link to this heading\">#</a></h3><p>Al sustituir <span class=\"math notranslate nohighlight\">\\(x(t) = e^{\\lambda t}\\)</span> se obtiene:</p>", "a[href=\"#sistema-no-amortiguado-zeta-0\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Sistema no amortiguado (<span class=\"math notranslate nohighlight\">\\(\\zeta = 0\\)</span>)<a class=\"headerlink\" href=\"#sistema-no-amortiguado-zeta-0\" title=\"Link to this heading\">#</a></h3>", "a[href=\"#sistema-masa-resorte-amortiguador\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Sistema masa resorte amortiguador<a class=\"headerlink\" href=\"#sistema-masa-resorte-amortiguador\" title=\"Link to this heading\">#</a></h1><p>Un <strong>sistema masa resorte amortiguador</strong> consta de tres componentes esenciales</p>", "a[href=\"#modelo-clasico\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Modelo cl\u00e1sico<a class=\"headerlink\" href=\"#modelo-clasico\" title=\"Link to this heading\">#</a></h2>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(`article.bd-article ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: false,
                placement: 'auto-start', maxWidth: 500, interactive: true, boundary: document.body, appendTo: document.body,
                onShow(instance) {MathJax.typesetPromise([instance.popper]).then(() => {var isFirefox=typeof InstallTrigger!=='undefined';if(isFirefox&&window.MathJax&&MathJax.startup&&MathJax.startup.output&&MathJax.startup.output.name==="SVG"){const svgs=instance.popper.querySelectorAll('svg');svgs.forEach(svg=>{let bbox=svg.getBBox(),x=bbox.x,y=bbox.y,width=bbox.width,height=bbox.height;svg.setAttribute('width',width);svg.setAttribute('height',height);svg.setAttribute('viewBox',`${x} ${y} ${width} ${height}`);});let rescale=0.015;svgs.forEach(svg=>{let bbox=svg.getBBox(),width=bbox.width,height=bbox.height;svg.setAttribute('width',width*rescale);svg.setAttribute('height',height*rescale);});}});},
            });
        };
    };
    console.log("tippy tips loaded!");
};
